def get_tiaohou(ri_gan: str, month_zhi: str) -> str:
    """获取调候用神"""
    return TIAOHOUS.get(ri_gan + month_zhi, "")


def get_jinbuhuan(ri_gan: str, month_zhi: str) -> str:
    """获取金不换大运建议"""
    return JINBUHUAN.get(ri_gan + month_zhi, "")


def get_jins(ri_gan: str) -> str:
    """获取金不换说明"""
    return JINS.get(ri_gan, "")
